const input = $input.first().json;
const action = (() => {
  try { return ($('Input Normalizer').first().json.action || 'create').toLowerCase(); } catch(e) { return 'create'; }
})();
const oldOrderId = input.Order_ID;
const newOrderId = (() => {
  try { return $('Input Normalizer').first().json.New_Order_ID || null; } catch(e) { return null; }
})();

const staticData = $getWorkflowStaticData('global');
const supabaseActive = staticData.supabase_mirror_enabled !== false;

const SUPABASE_KEY = (() => { try { return process.env.SUPABASE_SERVICE_KEY; } catch(e) { return null; } })()
  || 'sb_secret_EXq938yU-MinIxdpOc0nZg_qL-N3BCq';

// Build lookup from original webhook items to preserve UI-edited process_status & batch_number
let uiItemMap = {};
try {
  const triggerBody = $('Receive Dashboard Order').first().json.body || $('Receive Dashboard Order').first().json;
  (triggerBody.Order_Items_List || []).forEach(function(it) {
    if (it.Order_Item_Key) {
      uiItemMap[it.Order_Item_Key] = {
        process_status: it._ui_process_status || null,
        batch_number: it._ui_batch_number || null
      };
    }
  });
} catch(e) { /* Receive Dashboard Order not in scope */ }

let rawFormState = {};
try {
  rawFormState = typeof input.Raw_Form_State === 'string'
    ? JSON.parse(input.Raw_Form_State || '{}')
    : (input.Raw_Form_State || {});
} catch(e) { rawFormState = { raw: String(input.Raw_Form_State) }; }

// [item_sale_price] Parse balanceSplitData + depositSplitData → _splitMap
// splitData format: {"TEMP_P_MAIN##": 1680, "TEMP_K_rf#🦶 右腳#嬰兒": 2000}
// Key suffix rule: "TEMP_P_MAIN##" → "P_MAIN", "TEMP_K_rf#..." → "K_RF"
const _splitMap = {};
['balanceSplitData', 'depositSplitData'].forEach(function(dataKey) {
  let splitData = rawFormState[dataKey];
  if (typeof splitData === 'string') {
    try { splitData = JSON.parse(splitData); } catch(e) { splitData = {}; }
  }
  if (splitData && typeof splitData === 'object' && !Array.isArray(splitData)) {
    Object.keys(splitData).forEach(function(key) {
      const suffix = key.replace('TEMP_', '').split('#')[0].toUpperCase();
      _splitMap[suffix] = (_splitMap[suffix] || 0) + (Number(splitData[key]) || 0);
    });
  }
});

// [B7 fix] final_sale_price = Deposit + Balance + Additional_Fee（確收守護）
// Total_Revenue 是系統建議售價，不可作為確收依據，禁止覆蓋操作者確認金額
const _confirmedRevenue = (input.Deposit || 0) + (input.Balance || 0) + (input.Additional_Fee || 0);

// Sum validation: splitMap total must equal final_sale_price ±$1 (epsilon for rounding)
const _splitTotal = Object.values(_splitMap).reduce(function(s, v) { return s + v; }, 0);
const _hasSplitData = Object.keys(_splitMap).length > 0;
const _splitValid = !_hasSplitData || Math.abs(_splitTotal - _confirmedRevenue) <= 1;
// If validation fails: item_sale_price = null → RPC 3-layer fallback takes over

const order = {
  customer_name: input.Customer_Name || oldOrderId,
  appointment_at: input.Appointment_Date || null,
  final_sale_price: _confirmedRevenue,
  total_cost: input.Total_Cost || 0,
  net_profit: _confirmedRevenue - (input.Total_Cost || 0),
  deposit: input.Deposit || 0,
  balance: input.Balance || 0,
  additional_fee: input.Additional_Fee || 0,
  full_order_text: input.Order_Text || '',
  handmodel_cost: input.Handmodel_Cost_Total || 0,
  keychain_cost: input.Keychain_Cost_Total || 0,
  necklace_cost: input.Necklace_Cost_Total || 0,
  n8n_cost_adjustments: Number(input.N8n_Cost_Adjustments) || 0,
  n8n_adjustment_notes: input.N8n_Adjustment_Notes || [],
  raw_form_state: rawFormState
};

if (action === 'create') {
  order.process_status = '待確認';
  if (input.Order_Confirm_Date) {
    order.confirmed_at = input.Order_Confirm_Date;
  }
}

const items = (input.Sub_Items || []).map((item, index) => {
  const ui = uiItemMap[item.Order_Item_Key] || {};
  // [Session 84 B-fix] 鎖匙扣/吊飾的刻字存放在 item.Notes（[上排]X [下排]Y / 單字），
  // 需導入 engraving_text 欄位；手模(立體擺設)刻字走 raw_form_state.pEngraving（由前端 mapOrder fallback 處理），不在此。
  const _isEngCat = (item.Item_Category === '金屬鎖匙扣' || item.Item_Category === '純銀頸鏈吊飾');

  // [item_sale_price] Map item_key suffix → _splitMap entry
  const _itemKeySuffix = (item.Order_Item_Key || '').replace(oldOrderId + '_', '').toUpperCase();
  const _itemSalePrice = (_splitValid && _hasSplitData && _splitMap[_itemKeySuffix] != null)
    ? _splitMap[_itemKeySuffix]
    : null;

  return {
    item_key: item.Order_Item_Key || (oldOrderId + '_' + index + '_AUTO'),
    product_sku: item.Product_Name || null,
    item_category: item.Item_Category || null,
    quantity: item.Quantity || 1,
    item_base_cost: item.Total_Base_Cost || 0,
    subtotal_cost: item.Total_Base_Cost || 0,
    handmodel_cost: item.Handmodel_Cost || 0,
    keychain_cost: item.Keychain_Cost || 0,
    necklace_cost: item.Necklace_Cost || 0,
    specification: item.Notes || '',
    engraving_text: _isEngCat ? (item.Notes || '') : '',
    process_status: ui.process_status || null,
    batch_number: ui.batch_number || null,
    // Task A: 四分量成本欄位（0027 已建欄，此處填值）
    drawing_cost:  Number(item.Drawing_Cost)  || 0,
    printing_cost: Number(item.Printing_Cost) || 0,
    chain_cost:    Number(item.Chain_Cost)    || 0,
    shipping_cost: Number(item.Shipping_Cost) || 0,
    // [item_sale_price] 精確品項售價（V42+ splitData 有值則填，否則 null → RPC fallback）
    item_sale_price: _itemSalePrice
  };
});

return [{
  json: {
    supabaseActive,
    supabaseKey: SUPABASE_KEY,
    rpcPayload: {
      p_action: action,
      p_old_order_id: oldOrderId,
      p_new_order_id: newOrderId,
      p_order: order,
      p_items: items
    }
  }
}];
